-- Enrichment marathon batch: Looker, Looker Studio, Loom, Loomio, Loomly, Loops, Lovable, LOVO

-- в”Ђв”Ђ Looker в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Enterprise business intelligence platform from Google Cloud built on the LookML semantic modeling layer for governed analytics.$q$, short_description),
  pricing_model = COALESCE($q$Custom/Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$Part of Google Cloud (Alphabet); Looker had roughly 800 employees at the time of acquisition$q$, company_size),
  headquarters = COALESCE($q$Mountain View, California, US (Google Cloud); originally founded in Santa Cruz, California$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Looker Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Looker review 2026: how Google Cloud's LookML-based BI platform works, embedded analytics, pricing structure, and how it compares to Tableau and Power BI.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Looker is an enterprise business intelligence and data platform now owned by Google and sold through Google Cloud. It was founded in January 2012 in Santa Cruz, California, by Lloyd Tabb and Ben Porterfield, who had previously worked on data and infrastructure projects at companies including Netscape and LiveOps. Looker's founding idea was that traditional BI tools forced analysts into static, disconnected reports built from copied-out data extracts. Instead, Looker introduced LookML, a version-controlled, git-backed modeling language that lets data teams define metrics, dimensions, and table relationships once in a central semantic layer. Business users then explore that governed data directly against the live warehouse rather than a stale cube, running native SQL against systems like BigQuery, Snowflake, Redshift, and PostgreSQL. This in-database, semantic-layer-first architecture set Looker apart from legacy BI incumbents and helped it grow quickly among data-driven technology and SaaS companies during the mid-2010s. Google acquired Looker in 2019 for approximately 2.6 billion dollars, with the deal closing in February 2020. Since then, Looker has become the umbrella brand for Google Cloud's business intelligence portfolio, and the underlying LookML semantic layer has increasingly been connected to Gemini-powered conversational analytics. Looker's free, self-serve sibling product was rebranded from Google Data Studio to Looker Studio in October 2022, then reverted to the Data Studio name in April 2026, a change that does not affect the enterprise Looker platform itself. Architecturally, Looker targets centralized data teams rather than individual report builders. Analysts and data engineers write LookML models describing dimensions, measures, joins, and row- or column-level access rules; business users then browse, filter, and visualize that governed data through Looker's Explore interface without writing SQL. The platform supports scheduled delivery and alerting, a full REST API and SDKs for building custom data applications on top of the semantic layer, and an embedded analytics offering that lets SaaS companies white-label Looker dashboards inside their own products. Core features include the LookML modeling language as a single reusable semantic layer; native, extract-free querying against modern cloud warehouses; embedded and white-labeled analytics with granular access controls; an extensive API and developer platform; enterprise-grade governance and security, including row-level permissions; scheduled reports and Slack/email integrations; and generative-AI features such as natural-language querying layered on top of the governed model. Pricing is not published; Looker is sold through custom, quote-based enterprise contracts negotiated with the Google Cloud sales team, typically structured around platform access and the number of viewer and developer seats, with BigQuery or other warehouse compute billed separately. This makes Looker a considered enterprise purchase aimed at mid-market and large organizations, dedicated data platform teams, and software companies embedding analytics into their own products, rather than individual marketers or small teams, who are instead better served by Looker's own free sibling product or lighter self-serve dashboard tools. Looker's main competitors are other enterprise BI and semantic-layer platforms, including Tableau (owned by Salesforce), Microsoft Power BI, Qlik Sense, Domo, Sisense, and newer standalone semantic-layer challengers such as Cube and Omni. Looker differentiates itself through the maturity of LookML as a portable, version-controlled modeling layer; deep native integration with BigQuery and the broader Google Cloud AI stack; and strong embedded-analytics tooling for software vendors. Its main trade-offs are a steeper implementation curve, since LookML modeling requires dedicated data engineering investment before business users see value, and enterprise-only custom pricing that puts it out of reach for smaller teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f1fa4604-a254-46d0-ac89-4c0c21148bf3';

