-- в”Ђв”Ђ Loomio в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
UPDATE tools SET
  short_description = COALESCE($q$Open-source collaborative decision-making software built by a worker-owned cooperative, unrelated to Loom despite the similar name.$q$, short_description),
  pricing_model = COALESCE($q$Freemium/Open Source$q$, pricing_model),
  starting_price = COALESCE($q$$39/month$q$, starting_price),
  founded_year = COALESCE(2011, founded_year),
  company_size = COALESCE($q$Small team, roughly 8 to 10 people$q$, company_size),
  headquarters = COALESCE($q$Wellington, New Zealand$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Loomio Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Loomio review 2026: open-source group decision-making features, pricing plans, its cooperative origins, and how it differs from Loom and Loomly.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Loomio is open-source collaborative decision-making software built and maintained by a worker-owned cooperative based in Wellington, New Zealand. Despite the similar-sounding name, Loomio has no corporate relationship to Loom, the video messaging company acquired by Atlassian, or to Loomly, the social media scheduling platform; the three are entirely separate products built by unrelated companies. Loomio's origins trace to 2011, when activists connected to the Occupy Wellington movement and social entrepreneurs from the Enspiral network in New Zealand identified a shared problem: non-hierarchical groups wanted every member to have a voice in decisions, but traditional top-down voting felt exclusionary while full consensus meetings requiring everyone in a room were too slow to scale. Members of both groups collaborated to design software that could support fast, inclusive, asynchronous decision-making without requiring a physical meeting. The team formally organized as a cooperative and released a Loomio Beta prototype in 2012, then ran a successful international crowdfunding campaign in 2013 that funded development of Loomio 1.0, released in 2014. In 2015 the cooperative raised a round of what it describes as ethical capital to continue expanding the tool's reach. Loomio has operated as a worker-owned cooperative social enterprise ever since, remaining a small team of roughly eight to ten people handling development, support, marketing, and operations out of Wellington. The software itself is released as free software under the GNU Affero General Public License, meaning the source code is publicly available and organizations can self-host it, while the cooperative also offers a hosted, paid version as its primary revenue source. Architecturally, Loomio is a structured group discussion and proposal tool rather than a general chat app: conversations are organized into threads tied to specific groups, and any member can raise a formal proposal with a deadline and a set of response options (agree, abstain, disagree, block), after which Loomio visually summarizes the outcome so the group can see where consensus does or does not exist. This proposal-and-outcome structure is Loomio's core differentiator from generic messaging tools like Slack or forum software like Discourse, which support discussion but have no native mechanism for converting conversation into a recorded, auditable group decision. Core features include threaded group discussions organized by subgroup; formal proposals with customizable response options and deadlines; a visual decision record showing how each member responded and the final outcome; file attachments and rich formatting within threads; email and notification digests so members can participate without checking the app constantly; data export tools so organizations retain full ownership of their discussion and decision history; and, for the self-hosted open-source version, complete control over data location and infrastructure. Pricing follows a freemium-adjacent commercial model layered on top of the open-source core: a Starter plan costs 39 dollars a month (399 dollars billed annually) for one group with up to 30 members, including an onboarding call and email support; a Pro plan costs 99 dollars a month (999 dollars billed annually) for up to 3,000 members with unlimited subgroups; both plans offer significant nonprofit discounts, roughly 25 to 50 percent off, for eligible nonprofits, incorporated societies, volunteer-based, or member-funded organizations, with a choice of USA or Netherlands-based hosting. A Private Loomio tier offers custom pricing for organizations that need dedicated infrastructure, single sign-on, custom branding, and unlimited users and groups. Because pricing is organization-wide rather than strictly per-seat, Loomio tends to be economical for larger nonprofits and cooperatives compared with per-user collaboration tools. Loomio's target audience is distinctly different from typical enterprise SaaS: cooperatives, nonprofits, community organizations, activist and advocacy groups, local government participatory budgeting initiatives, worker-owned businesses, and any group that wants a transparent, non-hierarchical decision-making process. Its competitors are less about direct feature-for-feature rivals and more about adjacent tools that get repurposed for group decisions, including Slack, Discourse, Consensus, and Cobudget, none of which offer Loomio's purpose-built proposal-and-outcome workflow. Loomio differentiates itself through its cooperative ownership structure, open-source licensing, self-hosting option, and its specific focus on making group decisions visible, auditable, and inclusive rather than simply facilitating conversation.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0';

