INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$LookML semantic layer$q$, $q$A version-controlled modeling language that defines metrics and relationships once for consistent reuse across every report and app.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Live, in-database querying$q$, $q$Runs native SQL against warehouses like BigQuery, Snowflake, and Redshift instead of relying on static data extracts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Embedded analytics$q$, $q$White-labeled dashboards and visualizations can be embedded into third-party products via Looker's embed SDK and API.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Governed access controls$q$, $q$Row-level and column-level permissions let enterprises enforce data security and compliance at the semantic layer.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Looker Platform and API$q$, $q$A full REST API and extension framework for building custom data applications on top of governed Looker models.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Scheduled delivery and alerting$q$, $q$Automated report delivery, alerts, and integrations with Slack and email keep stakeholders updated without manual exports.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Google Cloud and Gemini integration$q$, $q$Deep native connectivity to BigQuery and increasing integration with Gemini-powered conversational analytics.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Multi-cloud connectivity$q$, $q$Connects beyond Google Cloud to Snowflake, Redshift, PostgreSQL, and other major warehouses.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Version-controlled LookML semantic layer keeps metrics consistent across the whole organization$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Strong embedded-analytics tooling for SaaS companies white-labeling dashboards$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Queries live warehouse data instead of stale extracts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Deep native integration with BigQuery and Google Cloud's AI stack$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Enterprise-grade governance with row-level and column-level security$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Pricing is entirely custom and requires a sales conversation, with no public self-serve tier$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Steep implementation curve; LookML modeling requires dedicated data engineering resources$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Overkill and cost-prohibitive for small teams or individual analysts$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Learning LookML syntax adds onboarding time compared to drag-and-drop BI tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Full value depends on a mature underlying data warehouse being in place first$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Is Looker the same product as Looker Studio$q$, $q$No. Looker is Google Cloud's paid, enterprise semantic-layer BI platform built on LookML, while Looker Studio (renamed Data Studio again in April 2026) is a separate, free self-serve reporting and visualization tool. They share a brand history but are different products for different audiences.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Who founded Looker$q$, $q$Looker was founded in January 2012 in Santa Cruz, California, by Lloyd Tabb and Ben Porterfield.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$When did Google acquire Looker$q$, $q$Google announced its acquisition of Looker in June 2019 for approximately 2.6 billion dollars, with the deal closing in February 2020.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$What is LookML$q$, $q$LookML is Looker's proprietary, version-controlled modeling language used to define dimensions, measures, and relationships in a governed semantic layer that sits between raw warehouse tables and business users.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$How much does Looker cost$q$, $q$Looker does not publish pricing publicly. It is sold through custom enterprise contracts negotiated with the Google Cloud sales team, based on edition, seats, and data volume.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Who is Looker built for$q$, $q$Looker targets mid-market and large enterprises with dedicated data teams, plus software companies that want to embed governed analytics inside their own products.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Embedded analytics for SaaS products$q$, $q$Software companies use Looker's embed SDK to white-label governed dashboards directly inside their own customer-facing applications.$q$, $q$Product and engineering teams at B2B SaaS companies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Centralized enterprise reporting$q$, $q$Large organizations use LookML to define a single source of truth for metrics that every department queries consistently.$q$, $q$Enterprise data and analytics engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Governed self-service exploration$q$, $q$Business users explore live warehouse data through Looker's Explore interface without writing SQL, while access stays governed by the semantic layer.$q$, $q$Business analysts and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$Custom Enterprise Plan$q$, $q$Custom pricing$q$, $q$Annual contract (custom)$q$, NULL, $q$["LookML semantic layer","Embedded analytics and API access","Enterprise security and governance controls","BigQuery and multi-cloud warehouse connectivity","Dedicated Google Cloud sales and support"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Looker is a governed business intelligence platform built around LookML, a version-controlled semantic modeling language, and sold as part of Google Cloud since Google's 2.6 billion dollar acquisition of the company in 2019.$q$, $q$Rather than working from static extracts, Looker queries live data directly in the warehouse, which keeps dashboards and embedded analytics in sync with the source system at all times.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$LookML lets data teams define metrics, joins, and access rules once, then reuse that governed logic across every dashboard, embedded app, and ad hoc exploration in the organization.$q$, $q$Looker's embed SDK and API are widely used by SaaS companies that want to white-label analytics inside their own customer-facing products, turning Looker into an application-development platform as much as a reporting tool.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f1fa4604-a254-46d0-ac89-4c0c21148bf3', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Looker does not publish self-serve pricing; access is sold through custom Google Cloud enterprise contracts based on platform edition, number of seats, and connected data volume.$q$, $q$Because pricing requires a sales conversation, Looker is generally a fit for organizations that already have a dedicated data or analytics engineering function to build out the LookML model.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Free unlimited reporting$q$, $q$Individuals and small teams can build and share unlimited interactive reports at no cost.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Native Google ecosystem connectors$q$, $q$Direct connections to Google Analytics, Google Ads, Sheets, and BigQuery without extra setup.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Data blending$q$, $q$Combines data from multiple sources into a single chart or table for cross-channel reporting.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Real-time collaboration$q$, $q$Multiple users can edit and comment on reports simultaneously, similar to Google Docs.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Embeddable reports$q$, $q$Reports can be embedded directly into websites or shared via link with viewer permissions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Looker Studio Pro (paid tier)$q$, $q$Adds team content management, approval workflows, and enterprise security for organizations scaling report usage.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Third-party connector marketplace$q$, $q$Community and partner connectors extend reach to platforms like Meta Ads, HubSpot, and Semrush.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$AI-assisted report building$q$, $q$Emerging generative-AI tools help generate charts, explain data, and speed up report creation.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Core reporting product is completely free with no usage cap for individuals$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Deep native integration with Google Analytics, Ads, Sheets, and BigQuery$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$No infrastructure or IT setup required to start building reports$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Easy sharing and embedding modeled on familiar Google Docs-style permissions$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Large community connector ecosystem for non-Google data sources$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Non-Google data sources often require paid third-party connectors like Supermetrics or Funnel$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Lacks the governed semantic layer and row-level security of the paid Looker BI platform$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Performance can lag on large or complex data blends$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Brand has changed names twice in under four years, causing confusion for users and documentation$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Pro tier billing is per licensed user per project, which can get expensive for multi-project agencies$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Is Looker Studio the same as Looker$q$, $q$No. Looker Studio (now renamed back to Data Studio) is a free, individual-oriented reporting tool, while Looker is a separate, paid enterprise BI platform built on LookML and sold through custom Google Cloud contracts.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Why was Looker Studio renamed back to Data Studio$q$, $q$On April 11, 2026, Google reversed its 2022 rebrand and renamed Looker Studio back to Data Studio, positioning it as a unified hub for reports, BigQuery AI agents, and Colab data apps across Google's data ecosystem.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Is Looker Studio actually free$q$, $q$Yes, the core reporting and visualization product is free for unlimited individual use. A paid Pro tier exists for teams that need workspace management, approval workflows, and enterprise security.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$What was Looker Studio previously called$q$, $q$It launched in 2016 as Google Data Studio, was renamed Looker Studio in October 2022, and was renamed back to Data Studio in April 2026.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Does Looker Studio connect to non-Google data sources$q$, $q$Yes, through community and partner connectors, though many non-Google integrations (such as Meta Ads or HubSpot) require a separate paid connector service.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$How much does the paid Pro tier cost$q$, $q$Looker Studio Pro is priced at roughly 9 dollars per user per project per month on annual billing, charged per licensed seat regardless of activity.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Marketing performance dashboards$q$, $q$Marketers connect Google Analytics and Ads accounts to build recurring campaign performance reports without engineering help.$q$, $q$Digital marketers and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Agency client reporting$q$, $q$Agencies use templated, brandable reports to deliver recurring performance updates to multiple clients.$q$, $q$Marketing and SEO agencies$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Ad hoc business dashboards$q$, $q$Analysts blend Sheets, BigQuery, and other sources into quick dashboards for internal stakeholders.$q$, $q$Business analysts and operations teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Unlimited reports for individual use","Native Google Analytics, Ads, Sheets, and BigQuery connectors","Sharing and embedding","Community connector access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$Pro$q$, $q$Around $9 per user per project per month (annual billing)$q$, $q$Monthly or annual, billed per project$q$, NULL, $q$["Team workspace and content management","Approval workflows","Enterprise security and admin controls","Deeper Google Cloud and Workspace integration"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Looker Studio began life in 2016 as Google Data Studio, was renamed Looker Studio in October 2022 as part of Google's BI brand unification, and reverted to the Data Studio name again in April 2026.$q$, $q$It is a free, self-serve reporting and dashboard tool, distinct from the paid enterprise Looker BI platform, even though both now sit under Google's data analytics umbrella.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The tool connects natively to Google Analytics, Google Ads, Sheets, and BigQuery, and to hundreds of third-party sources through community and partner connectors.$q$, $q$Data blending lets users combine multiple sources into a single chart, while sharing and embedding work much like Google Docs, making it easy to distribute reports without extra infrastructure.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('3ddd1302-f04e-4a3a-8111-e7b0aaeadc87', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The core reporting product remains free for unlimited individual use, connecting to Google and third-party data sources at no cost.$q$, $q$A paid Pro tier, priced per user per project and billed around 9 dollars per user monthly on an annual plan, adds team workspace management, approval workflows, and enterprise security controls.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Instant screen and camera recording$q$, $q$Capture screen, webcam, or both with no need to schedule a live meeting.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Shareable links with viewer analytics$q$, $q$Every recording generates a link showing who watched, how much, and their reactions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Automatic transcription and captions$q$, $q$AI-generated transcripts and captions are available in more than 50 languages.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Loom AI meeting notes and summaries$q$, $q$Automatically turns recordings into written summaries, notes, and action items.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Video editing tools$q$, $q$Trim clips, remove filler words, and add call-to-action overlays without leaving the browser.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Comments and reply videos$q$, $q$Viewers can leave timestamped comments, emoji reactions, or record their own reply video.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Team workspaces and folders$q$, $q$Organize recordings by team or project with shared workspace permissions.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Deep integrations$q$, $q$Connects with Slack, Notion, Jira, Confluence, Gmail, and Salesforce for embedding video into existing workflows.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Free plan is genuinely usable for lightweight, occasional async communication$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Fast, low-friction recording experience with instant shareable links$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Strong AI-powered transcription, summarization, and meeting notes$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Deep integration with Atlassian tools like Jira and Confluence post-acquisition$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Viewer analytics show engagement, which is useful for sales and support use cases$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Free plan caps videos at 25 total and limits screen recordings to 5 minutes$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Per-seat pricing on Business and Business plus AI plans adds up for larger teams$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Some advanced AI features are gated behind the higher-priced tier$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Increasing competition from screen recording features built into Zoom, Slack, and Teams$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Enterprise-grade security features require custom, sales-negotiated pricing$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Who owns Loom now$q$, $q$Loom is owned by Atlassian, which acquired the company for 975 million dollars in a deal announced October 12, 2023, and completed November 30, 2023.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Is Loom free to use$q$, $q$Yes, Loom's Starter plan is free and includes 25 videos with 5-minute screen recordings and unlimited-length meeting recordings, though paid plans remove those limits.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Who founded Loom$q$, $q$Loom was founded in 2015 in San Francisco by Vinay Hiremath, Shahed Khan, and Joe Thomas.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$How much does Loom Business cost$q$, $q$Loom Business costs 18 dollars per user per month, while Business plus AI, which adds AI meeting notes and advanced editing, costs 24 dollars per user per month.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$What languages does Loom support for transcription$q$, $q$Loom offers automatic transcription and captions in more than 50 languages.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$What are the main alternatives to Loom$q$, $q$Common alternatives include Vidyard, Zoom Clips, Screencastify, and Wistia's Soapbox.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Async product and engineering updates$q$, $q$Teams record short videos to explain bugs, walk through code, or demo features instead of holding a live meeting.$q$, $q$Product and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Sales and customer outreach$q$, $q$Sales reps send personalized recorded demos and follow-ups, using viewer analytics to gauge prospect engagement.$q$, $q$Sales and customer success teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Internal training and documentation$q$, $q$Organizations record how-to videos and onboarding walkthroughs that are automatically transcribed for searchable documentation.$q$, $q$HR, operations, and enablement teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Starter$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["25 videos total","5-minute screen recordings","Unlimited meeting recording length","Transcription in 50+ languages"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Business$q$, $q$$18 per user per month$q$, $q$Monthly or annual (annual saves up to 17%)$q$, NULL, $q$["Unlimited videos and recording length","4K video quality","Basic editing tools","Remove Loom branding"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Business plus AI$q$, $q$$24 per user per month$q$, $q$Monthly or annual (annual saves up to 17%)$q$, NULL, $q$["Everything in Business","AI-generated meeting notes and recaps","Advanced editing","Video-to-text automation"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["SSO and SCIM provisioning","Salesforce integration","99.95% uptime SLA","Dedicated account management"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Loom is an async video messaging tool that lets users record and instantly share screen or camera video instead of scheduling a live meeting, founded in San Francisco in 2015 and acquired by Atlassian for 975 million dollars in late 2023.$q$, $q$The platform grew to roughly 25 million users before the acquisition and now operates as part of Atlassian's broader collaboration suite alongside Jira and Confluence.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Loom captures screen and camera simultaneously, auto-uploads the recording, and generates a shareable link with viewer analytics, comments, and reactions.$q$, $q$AI features layered on top of recordings include automatic transcription in more than 50 languages, meeting note generation, and video-to-text automation for turning recordings into written summaries.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2f887979-d5df-489e-930d-a372b71f2354', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The free Starter plan allows 25 videos with 5-minute screen recordings, while Business ($18/user/month) and Business plus AI ($24/user/month) unlock unlimited recording length and AI-powered editing features.$q$, $q$An Enterprise plan with SSO, SCIM, and a 99.95 percent uptime SLA is available at custom pricing, and all paid plans include a 14-day free trial.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Threaded group discussions$q$, $q$Conversations are organized by group and subgroup rather than a single flat chat stream.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Formal proposals with response options$q$, $q$Any member can raise a proposal with a deadline and agree, abstain, disagree, or block responses.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Visual decision record$q$, $q$Loomio summarizes how each member responded and the final outcome for a transparent, auditable history.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Open-source and self-hostable$q$, $q$Released under the AGPL license, allowing organizations to run their own instance and control their data.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Nonprofit discounts$q$, $q$Eligible nonprofits, cooperatives, and volunteer-based organizations receive discounted commercial pricing.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Data export and ownership$q$, $q$Organizations can export members, discussions, polls, and decisions at any time.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Unlimited subgroups (Pro)$q$, $q$Larger organizations can structure discussions into unlimited subgroups under one account.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Choice of hosting region$q$, $q$Hosted plans offer a choice of USA or Netherlands-based data hosting.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Purpose-built proposal-and-outcome workflow that generic chat tools lack$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Open-source with a self-hosting option for full data control$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Organization-wide pricing rather than strict per-seat billing$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Significant discounts for nonprofits and cooperatives$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Built and maintained by a mission-aligned worker-owned cooperative$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Smaller team and ecosystem than venture-backed collaboration tools$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Interface is more utilitarian than modern chat-first competitors$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Self-hosting the open-source version requires technical setup and maintenance$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Limited to 30 members on the entry-level Starter plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Less brand recognition than mainstream collaboration tools like Slack$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Is Loomio related to Loom or Loomly$q$, $q$No. Loomio, Loom, and Loomly are three completely unrelated products built by different companies; the similar names are coincidental.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Is Loomio free to use$q$, $q$The core software is open source and can be self-hosted for free under the AGPL license. The cooperative's hosted version starts at $39/month for one group with up to 30 members.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Who runs Loomio$q$, $q$Loomio is built and operated by Loomio Cooperative, a worker-owned social enterprise based in Wellington, New Zealand, active since 2011.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$What makes Loomio different from Slack for decision-making$q$, $q$Loomio adds a structured proposal feature with deadlines and response options (agree, abstain, disagree, block) and a visual decision record, which general chat tools like Slack do not natively provide.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Does Loomio offer nonprofit pricing$q$, $q$Yes, eligible nonprofits, incorporated societies, volunteer-based, and member-funded organizations receive discounted rates on both Starter and Pro plans.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Can I self-host Loomio$q$, $q$Yes, the open-source version is available on GitHub and can be self-hosted, giving organizations full control over their data and infrastructure.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Cooperative and worker-owned business governance$q$, $q$Member-owned organizations use Loomio to run transparent votes and proposals on business decisions.$q$, $q$Worker cooperatives and member-owned businesses$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Nonprofit and activist group decisions$q$, $q$Advocacy groups and nonprofits use Loomio to include every member in decisions without requiring synchronous meetings.$q$, $q$Nonprofits and community advocacy organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Participatory local governance$q$, $q$Community and local government initiatives use Loomio for participatory budgeting and public input processes.$q$, $q$Local government and civic organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Starter$q$, $q$$39/month ($399/year)$q$, $q$Monthly or annual$q$, NULL, $q$["One group with up to 30 members","Onboarding call","Email support","Choice of USA or Netherlands hosting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Pro$q$, $q$$99/month ($999/year)$q$, $q$Monthly or annual$q$, NULL, $q$["Up to 3,000 members","Unlimited subgroups","Onboarding call and email support","Choice of USA or Netherlands hosting"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$Private Loomio$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Dedicated infrastructure","Single sign-on","Custom branding","Unlimited users and groups"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Loomio is open-source, purpose-built group decision-making software, built by a worker-owned cooperative in Wellington, New Zealand since 2011, and entirely unrelated to Loom or Loomly despite the similar name.$q$, $q$It grew out of the Occupy Wellington movement and the Enspiral network, whose members needed a tool for fast, inclusive decisions without requiring everyone to meet in person.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Loomio organizes conversation into threaded group discussions and lets any member raise a formal proposal with a deadline and response options like agree, abstain, disagree, or block.$q$, $q$The tool visually summarizes proposal outcomes into an auditable decision record, a structure that distinguishes it from generic chat or forum tools.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Loomio is released as free, open-source software under the AGPL license and can be self-hosted at no licensing cost.$q$, $q$The cooperative's hosted commercial plans start at $39/month for one group with up to 30 members, scaling to $99/month for up to 3,000 members, with nonprofit discounts available.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('b4c556a1-7dd3-4fb8-a70c-2e72bb6659e0', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Shared visual content calendar$q$, $q$Drag-and-drop scheduling across all connected social accounts in one calendar view.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Customizable approval workflows$q$, $q$Multi-step review and sign-off processes let managers or clients approve posts before publishing.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$AI-assisted post creation$q$, $q$Generates captions and copy suggestions to speed up content creation.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Post idea suggestions$q$, $q$Surfaces trending topics, RSS feeds, and observances to keep the content calendar full.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Unified social inbox$q$, $q$Manages comments and messages from multiple social channels in one shared inbox.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Brand guideline checks$q$, $q$Flags posts that deviate from brand voice or guidelines before they go live.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Performance analytics$q$, $q$Tracks post and channel performance across every connected social account.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Multi-channel publishing$q$, $q$Auto-publishes to Facebook, Instagram, X, LinkedIn, Pinterest, TikTok, YouTube, and Google Business Profile.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Approval workflows are more robust than most competitors at similar price points$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Published, transparent pricing tiers rather than sales-only enterprise quotes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Unlimited users included on every tier, which suits agencies and larger teams$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$AI-assisted ideation and brand guideline checks reduce manual content review$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Backed by Bending Spoons, giving the product continued investment after acquisition$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Pricing scales quickly with account count, making higher tiers expensive for large brands$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$No perpetual free plan, only a 7-day free trial$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Some advanced analytics and integrations are reserved for higher tiers$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Newer under Bending Spoons ownership, so long-term roadmap direction is still settling$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Smaller ecosystem of native integrations compared with larger competitors like Hootsuite$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Is Loomly related to Loom$q$, $q$No, Loomly is a social media management platform with no corporate connection to Loom, the video messaging tool, despite the similar name.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Who owns Loomly now$q$, $q$Loomly was acquired by Bending Spoons, an Italian technology holding company, on January 10, 2025. Financial terms were not disclosed.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$How much does Loomly cost$q$, $q$Loomly's Base plan starts at $42/month for 10 social accounts, scaling up to Premium at $369/month for 50 accounts, with a custom Enterprise tier for 61+ accounts.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Does Loomly offer a free trial$q$, $q$Yes, Loomly offers a 7-day free trial on paid plans with no credit card required, though there is no permanent free tier.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Who founded Loomly$q$, $q$Loomly was founded in 2015 by Thibaud Clement and Noemie Clement, and is headquartered in New York City.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$What makes Loomly different from Buffer or Hootsuite$q$, $q$Loomly places heavier emphasis on customizable multi-step approval workflows, post idea suggestions, and brand guideline checks, making it especially popular with agencies managing client sign-off.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Agency client content approval$q$, $q$Agencies route drafted posts through client approval workflows before scheduling, keeping every stakeholder aligned.$q$, $q$Digital marketing and social media agencies$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$In-house multi-brand social calendars$q$, $q$Marketing teams manage several brand accounts from one shared visual calendar with role-based permissions.$q$, $q$In-house marketing and social media teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Small business social presence management$q$, $q$Small business owners plan, get AI-assisted caption help, and schedule posts without a dedicated social media manager.$q$, $q$Small business owners and solo marketers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Base$q$, $q$$42/month$q$, $q$Monthly (annual billing offers ~25% discount)$q$, NULL, $q$["10 social accounts","Unlimited users","Unlimited calendars","Content approval workflows"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Standard$q$, $q$$80/month$q$, $q$Monthly (annual billing offers ~25% discount)$q$, NULL, $q$["20 social accounts","Unlimited users","Unlimited calendars","Advanced analytics"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Advanced$q$, $q$$175/month$q$, $q$Monthly (annual billing offers ~25% discount)$q$, NULL, $q$["35 social accounts","Unlimited users","Unlimited calendars","Extended workflow options"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Premium$q$, $q$$369/month$q$, $q$Monthly (annual billing offers ~25% discount)$q$, NULL, $q$["50 social accounts","Unlimited users","Unlimited calendars","Priority support"]$q$::jsonb, 3);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["61+ social accounts","Unlimited users","Dedicated support","Custom onboarding"]$q$::jsonb, 4);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Loomly is a social media management platform built around a shared content calendar and structured approval workflows, founded in New York in 2015 and acquired by Bending Spoons in January 2025.$q$, $q$It is unrelated to Loom or Loomio despite the similar naming pattern, and it competes in the crowded social scheduling category by focusing on approval-driven team and agency workflows.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Loomly's core is a visual calendar where posts move through customizable multi-step approval workflows before being scheduled and auto-published across connected social channels.$q$, $q$AI-assisted caption generation, trending post ideas, a unified social inbox, and brand guideline checks round out the platform beyond basic scheduling.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0b8a0924-eba0-43ca-b6e5-f3c97392c07e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Published pricing scales with the number of connected social accounts: Base at $42/month (10 accounts) up to Premium at $369/month (50 accounts), plus a custom Enterprise tier for 61+ accounts.$q$, $q$All tiers include unlimited users, and annual billing offers roughly a 25 percent discount versus paying monthly.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Unified marketing, lifecycle, and transactional email$q$, $q$Sends broadcast campaigns, automated sequences, and transactional email from one contact list and API.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Visual email editor and automation builder$q$, $q$No-code drag-and-drop tools for building campaigns and multi-step automations.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Developer API and SDKs$q$, $q$Lets engineering teams trigger transactional and event-based emails directly from application code.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Stripe and Segment integrations$q$, $q$Syncs billing and product event data into email segmentation and automation triggers.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Behavioral segmentation$q$, $q$Targets audiences based on subscriber properties and in-product behavioral events.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$A/B testing$q$, $q$Tests subject lines and content variations to optimize campaign performance.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Contact-based pricing with no seat fees$q$, $q$Entire teams can use the platform on one plan without per-user charges.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Deliverability-focused sending infrastructure$q$, $q$Built to reliably deliver both marketing and transactional email at scale.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Combines marketing, lifecycle, and transactional email in one tool instead of three$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$No per-seat pricing, so growing teams are not charged per user$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Free plan includes full feature access up to 1,000 contacts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Native Stripe and Segment integrations suit SaaS billing and product data$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Developer-friendly API appeals to engineering-led growth teams$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Much smaller company and ecosystem than legacy platforms like Mailchimp$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Feature set is narrower than dedicated customer engagement platforms like Customer.io for complex multi-channel journeys$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Pricing scales with contact count, which can rise quickly for high-volume SaaS products$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Fewer pre-built templates and design assets than larger competitors$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Limited to email; no native SMS, push, or in-app messaging channels$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Who is Loops built for$q$, $q$Loops is built specifically for SaaS and software companies that want marketing, lifecycle, and transactional email unified in a single platform.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Is Loops free to use$q$, $q$Yes, Loops offers a free plan for up to 1,000 subscribed contacts and 4,000 emails per month with full feature access, aside from a Loops branding footer.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Who founded Loops$q$, $q$Loops was founded in 2022 by Chris Frantz and Adam Kaczmarek, and went through Y Combinator's Winter 2022 batch.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$How much does Loops cost after the free plan$q$, $q$Paid plans start at $49/month for 1,000 to 5,000 subscribers, with pricing scaling by contact count rather than by team seats.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Can developers trigger emails from code with Loops$q$, $q$Yes, Loops provides a developer API and SDKs for triggering transactional and event-based emails directly from application code.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$How is Loops different from Mailchimp or Customer.io$q$, $q$Loops unifies marketing, lifecycle, and transactional email in one product with SaaS-specific integrations like Stripe and Segment, whereas Mailchimp focuses on marketing broadcasts and Customer.io focuses more on complex lifecycle messaging.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$SaaS onboarding and lifecycle automation$q$, $q$Product teams trigger onboarding sequences and trial-expiration nudges based on user behavior events.$q$, $q$SaaS product and growth teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Transactional email for applications$q$, $q$Engineering teams send password resets, receipts, and notifications through the Loops API alongside marketing email.$q$, $q$Software engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Startup marketing campaigns$q$, $q$Early-stage startups run newsletters and product announcement campaigns without managing separate marketing and transactional tools.$q$, $q$Early-stage and indie SaaS founders$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Free$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Up to 1,000 subscribed contacts","4,000 emails per month","All core features included","Loops branding in footer"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$Paid (contact-based)$q$, $q$From $49/month for 1,000 to 5,000 subscribers$q$, $q$Monthly, scales with contact count$q$, NULL, $q$["Unlimited email sends","Full transactional email support","No per-seat charges","No Loops branding"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Loops is an email marketing platform built specifically for SaaS companies, unifying marketing campaigns, lifecycle automations, and transactional email under one contact list and API.$q$, $q$Founded in 2022 by Chris Frantz and Adam Kaczmarek through Y Combinator's Winter 2022 batch, the company has raised $3.2 million led by Craft Ventures and stayed a small, San Francisco-based team.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform pairs a no-code visual email editor and automation builder with a developer-friendly API for triggering transactional and event-based emails directly from application code.$q$, $q$Native integrations with Stripe and Segment let product and growth teams sync billing and behavioral events into email automations without engineering support for every campaign.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('6a0e0878-222a-49ef-85d7-6e633b7c96fc', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$The Free plan covers up to 1,000 subscribed contacts and 4,000 emails a month with full feature access, aside from Loops branding in the footer.$q$, $q$Paid plans start at $49/month for 1,000 to 5,000 subscribers, scale purely with contact count, and include unlimited sends with no per-seat charges.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Natural-language app generation$q$, $q$Describes an application in plain language and generates a real, editable full-stack codebase in response.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Supabase-native backend$q$, $q$Built-in integration provides authentication, databases, and storage without separate backend setup.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Live visual and code editing$q$, $q$Users can edit the generated app visually or directly in code as requirements evolve.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$One-click deployment and custom domains$q$, $q$Ships generated apps to production with custom domain connection directly from the platform.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Iterative AI debugging$q$, $q$Follow-up prompts let users refine, fix, and extend the generated application over time.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Credit-based usage system$q$, $q$Meters both app-building actions and the compute used by deployed apps.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Unlimited workspace collaboration$q$, $q$Every plan, including Free, supports unlimited team members in a shared workspace.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Enterprise security controls$q$, $q$Business and Enterprise tiers add single sign-on and a dedicated security center.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Generates real, editable full-stack code rather than a locked black-box output$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Native Supabase integration provides working backend functionality out of the box$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Fast iteration loop from natural-language prompt to deployed application$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Unlimited team members included on every plan, including Free$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Backed by major investors, suggesting strong ongoing product investment$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Credit-based pricing can be difficult to predict, especially for actively used shipped apps$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Second usage-based billing layer for Cloud and AI adds cost on top of the subscription$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Generated code quality still requires review for complex or security-sensitive applications$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Younger platform than established coding tools, so best practices and workarounds are still emerging$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Heavy competition from well-funded rivals like v0, Bolt.new, and Replit$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$What was Lovable called before$q$, $q$Lovable evolved from GPT Engineer, an open-source AI code-generation project by Anton Osika, and its commercialized GPT Engineer App, before being renamed Lovable in December 2024.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Who founded Lovable$q$, $q$Lovable was founded by Anton Osika and Fabian Hedin in Stockholm, Sweden.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$How much does Lovable cost$q$, $q$Lovable offers a free plan with daily and monthly credits, a Pro plan at $25/month (100 credits), and a Business plan at $50/month with SSO, plus custom Enterprise pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$What is vibe coding$q$, $q$Vibe coding is the practice, popularized by Lovable, of describing a desired application in natural language and letting AI generate and iterate on the underlying code.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$What backend does Lovable use$q$, $q$Lovable integrates natively with Supabase to provide authentication, databases, and storage for generated applications.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$How much funding has Lovable raised$q$, $q$Lovable has raised a $7.5 million pre-seed round, additional funding in 2024, a $200 million Series A at a $1.8 billion valuation in early 2025, and a $330 million Series B at a $6.6 billion valuation.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Non-technical founder MVP building$q$, $q$Founders without engineering backgrounds describe their product idea in prompts and ship a working app without hiring developers.$q$, $q$Non-technical founders and solo entrepreneurs$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Rapid internal tool and prototype building$q$, $q$Product and design teams prototype internal tools or customer-facing features in hours instead of sprint cycles.$q$, $q$Product managers and designers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Developer-accelerated scaffolding$q$, $q$Professional engineering teams use Lovable to scaffold new features or apps quickly before refining the generated code by hand.$q$, $q$Professional software development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["5 daily build credits (up to 30/month)","20 monthly Cloud credits","Unlimited workspace members","Core app generation and editing"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Pro$q$, $q$$25/month ($21/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["100 monthly credits plus daily bonus credits","Full Supabase access","Custom domains","Unlimited workspace members"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Business$q$, $q$$50/month ($42/month billed annually)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Pro","Single sign-on","Security center","Team-focused controls"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["Custom credit allocation","Dedicated support","Advanced security and compliance","Custom onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Lovable is a Stockholm-based AI app builder that generates full-stack, deployable web applications from natural-language prompts, evolving out of Anton Osika's open-source GPT Engineer project before being renamed Lovable in December 2024.$q$, $q$The company has raised funding at an extraordinary pace, reaching a $6.6 billion valuation on a $330 million Series B backed by CapitalG, Menlo Ventures' Anthology fund, Nvidia's NVentures, Salesforce Ventures, and Databricks Ventures.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Users describe an app or feature in plain language, and Lovable generates and iteratively edits a real, editable codebase, typically React on the frontend paired with Supabase for backend services.$q$, $q$Generated apps can be deployed with custom domains directly from the platform, with further changes made through follow-up prompts or direct code edits.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Lovable uses a credit-based pricing model: Free includes daily build credits and monthly Cloud credits, Pro costs $25/month for 100 monthly credits, and Business costs $50/month with SSO and a security center.$q$, $q$A second, usage-based layer of Cloud and AI costs applies to shipped apps on top of the subscription, which can make total costs higher than the base plan price suggests.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5759ef4a-9adb-4775-9ea3-ae93aa85a490', '87a92d11-ee13-4164-9910-61410254388a') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Text-to-speech across 500+ voices$q$, $q$Generates natural-sounding voiceovers in roughly 100 languages and dialects.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Instant voice cloning$q$, $q$Creates a custom synthetic voice from a short sample recording, subject to consent safeguards.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Integrated video editor$q$, $q$Pairs generated voiceovers with visuals, captions, and stock media in the same workspace.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Emotion and style controls$q$, $q$Adjusts tone, pacing, and delivery to match the desired mood of a voiceover.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Developer API$q$, $q$Lets engineering teams embed LOVO's speech synthesis directly into their own applications.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Commercial usage rights$q$, $q$Paid plans include rights to use generated voices in ads, games, and monetized content.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Multilingual voiceover production$q$, $q$Supports localization workflows for marketing and e-learning content across many languages.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Team collaboration workspace$q$, $q$Supports shared projects for teams producing voice content at scale.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Large library of 500+ voices across roughly 100 languages and dialects$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Bundled video editor removes the need for a separate editing tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Voice cloning feature enables custom synthetic voices from short samples$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Entry-level pricing is more accessible than some enterprise-focused competitors$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Developer API supports embedding voice generation into other products$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Faces intense competitive pressure from fast-moving rivals like ElevenLabs on voice realism$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Small company size relative to the scale of its two million-plus user base$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Higher tiers (Pro+ at $149/month) are a significant jump from entry-level pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Voice cloning features carry consent and misuse risks common to the category$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Free trial is limited to about 20 minutes of generated audio$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$What is LOVO's main product called$q$, $q$LOVO's flagship product is Genny, which combines AI voice generation, text-to-speech, and an integrated video editor.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Who founded LOVO$q$, $q$LOVO was founded in November 2019 in Berkeley, California, by Tom Lee and Charlie Choi, originally under the name Orbis AI.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$How much does LOVO cost$q$, $q$LOVO's 2026 pricing includes Basic at $24/month, Pro at $48/month, and Pro+ at $149/month, plus a custom Enterprise tier and a 14-day free trial.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Does LOVO support voice cloning$q$, $q$Yes, LOVO offers instant voice cloning that creates a custom synthetic voice from a short audio sample.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$How many languages does LOVO support$q$, $q$LOVO offers more than 500 AI voices across roughly 100 languages and dialects.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Who are LOVO's main competitors$q$, $q$LOVO's main competitors in AI voice generation include ElevenLabs, Murf AI, Speechify, WellSaid Labs, and Play.ht.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$YouTube and social video voiceovers$q$, $q$Independent creators generate professional-sounding voiceovers without hiring voice actors or recording themselves.$q$, $q$Content creators and YouTubers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Corporate e-learning narration$q$, $q$L&D teams produce multilingual training and course narration at scale using text-to-speech instead of studio recording.$q$, $q$Corporate learning and development teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Multilingual advertising voiceovers$q$, $q$Marketing teams localize ad campaigns into multiple languages using LOVO's voice and language library.$q$, $q$Marketing and advertising teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Basic$q$, $q$$24/month$q$, $q$Monthly$q$, NULL, $q$["Text-to-speech generation","Access to a subset of voices and languages","Commercial usage rights","Standard audio minutes allowance"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Pro$q$, $q$$48/month$q$, $q$Monthly$q$, NULL, $q$["Expanded voice and language access","Increased audio minutes","Voice cloning allowance","Integrated video editor access"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Pro+$q$, $q$$149/month$q$, $q$Monthly$q$, NULL, $q$["Highest audio minutes allowance","Full voice and language library","Expanded cloning allowance","Priority support"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$Enterprise$q$, $q$Custom pricing$q$, $q$Annual contract$q$, NULL, $q$["High-volume usage","API access at scale","Dedicated account support","Custom onboarding"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$LOVO is an AI voice generation company founded in Berkeley, California in 2019 by Tom Lee and Charlie Choi, originally operating as Orbis AI before rebranding.$q$, $q$Its flagship product, Genny, combines text-to-speech, voice cloning, and an integrated video editor, serving more than two million creators and professionals worldwide.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Genny offers more than 500 AI voices across roughly 100 languages, built on neural text-to-speech models designed for natural prosody and emotional delivery.$q$, $q$Instant voice cloning from short audio samples, an integrated video editor, and an API for developers round out the platform beyond basic narration.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('279a89e2-68a4-41dd-89a0-fc4c8b2a5cce', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$LOVO's 2026 pricing includes a 14-day free trial with about 20 minutes of audio, then Basic at $24/month, Pro at $48/month, and Pro+ at $149/month.$q$, $q$Each tier increases monthly audio minutes, voice and language access, cloning allowances, and commercial usage rights, with custom Enterprise pricing for high-volume needs.$q$]::text[], 2);
